export function BrandMark({
  brand,
  className = "h-7 w-7",
}: {
  brand: BrandKey;
  className?: string;
}): ReactNode {
  // All marks render in brand orange so this row reads as a single
  // accented lineup rather than a multi-color logo zoo (matches the
  // framework marquee above).
  const style = { color: "var(--brand)" };
  return BRANDS[brand].render({
    className,
    style,
    "aria-hidden": true,
    focusable: "false",
  });
}

